const lineage = $('GET Lineage').first().json || {};
const scoresResp = $('GET Eval Scores').first().json || {};
const champion = $input.first().json || {};

const nodes = Array.isArray(lineage.nodes) ? lineage.nodes : [];
const trends = Array.isArray(scoresResp)
  ? scoresResp
  : Array.isArray(scoresResp.trends)
  ? scoresResp.trends
  : Array.isArray(scoresResp.scores)
  ? scoresResp.scores
  : [];

const now = new Date();
const since = new Date(now.getTime() - 7 * 24 * 3600 * 1000);
const sincePrev = new Date(now.getTime() - 14 * 24 * 3600 * 1000);

function inWindow(ts, a, b) {
  if (!ts) return false;
  const d = new Date(ts);
  return d >= a && d < b;
}

let promotedThis = 0;
let discardedThis = 0;
let promotedPrev = 0;
let discardedPrev = 0;
let trainingSecondsThis = 0;
const weakAccum = {};
const genDeltas = [];

let bestImp = -Infinity;
let bestImpDetail = null;
let prevAvg = null;
for (const n of nodes) {
  const ts = n.created_at || n.completed_at || n.timestamp;
  const decision = String(n.decision || (n.promoted ? 'promote' : 'discard')).toLowerCase();
  const inThis = inWindow(ts, since, now);
  const inPrev = inWindow(ts, sincePrev, since);
  if (inThis) {
    if (decision === 'promote') promotedThis += 1;
    else if (decision === 'discard') discardedThis += 1;
    trainingSecondsThis += Number(n.duration_seconds || 0);
    const wc = n.weak_categories || (n.data && n.data.weak_categories) || [];
    if (Array.isArray(wc)) for (const w of wc) weakAccum[w] = (weakAccum[w] || 0) + 1;
  }
  if (inPrev) {
    if (decision === 'promote') promotedPrev += 1;
    else if (decision === 'discard') discardedPrev += 1;
  }
  const avg = Number(n.avg_score ?? n.champion_avg ?? n.score);
  if (Number.isFinite(avg)) {
    if (prevAvg !== null) {
      const d = avg - prevAvg;
      genDeltas.push({ gen: Number(n.generation), delta: d });
      if (d > bestImp) {
        bestImp = d;
        bestImpDetail = { gen: Number(n.generation), delta: d };
      }
    }
    prevAvg = avg;
  }
}

const totalThis = promotedThis + discardedThis;
const totalPrev = promotedPrev + discardedPrev;
const rateThis = totalThis ? promotedThis / totalThis : 0;
const ratePrev = totalPrev ? promotedPrev / totalPrev : 0;

// Per-benchmark week-over-week
function collectByBench(predicate) {
  const out = {};
  for (const t of trends) {
    const ts = t.created_at || t.scored_at || t.completed_at || t.timestamp;
    if (!predicate(ts)) continue;
    const k = t.benchmark;
    const v = Number(t.score ?? t.child_score ?? 0);
    if (!Number.isFinite(v)) continue;
    if (!out[k]) out[k] = [];
    out[k].push(v);
  }
  return out;
}
function avgEach(obj) {
  const out = {};
  for (const [k, arr] of Object.entries(obj)) out[k] = arr.reduce((a, b) => a + b, 0) / arr.length;
  return out;
}
const thisWeekBench = avgEach(collectByBench((ts) => inWindow(ts, since, now)));
const prevWeekBench = avgEach(collectByBench((ts) => inWindow(ts, sincePrev, since)));
const weekOverWeek = {};
for (const k of Object.keys(thisWeekBench)) {
  const cur = thisWeekBench[k];
  const prev = prevWeekBench[k];
  weekOverWeek[k] = (Number.isFinite(prev) ? cur - prev : null);
}

const topWeak = Object.entries(weakAccum)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([k, v]) => `${k}(${v})`)
  .join(', ');

const championLabel = champion.model_id || champion.champion_model_id || 'unknown';
const championGen = champion.generation ?? champion.gen ?? 'n/a';
const lineageDepth = nodes.filter((n) => n.promoted || String(n.decision || '').toLowerCase() === 'promote').length;

const dateLabel = now.toISOString().slice(0, 10);

const lines = [
  `# ModelForge Weekly Summary — ${dateLabel}`,
  '',
  `**Champion**: \`${championLabel}\` (gen ${championGen})`,
  `**Lineage depth**: ${lineageDepth} promoted champions total`,
  '',
  `## Activity`,
  `- Generations this week: **${totalThis}** (promoted ${promotedThis}, discarded ${discardedThis})`,
  `- Generations last week: ${totalPrev} (promoted ${promotedPrev}, discarded ${discardedPrev})`,
  `- Promotion rate: ${(rateThis * 100).toFixed(1)}% (vs ${(ratePrev * 100).toFixed(1)}% last week)`,
  `- Best single-gen improvement: ${bestImpDetail ? (bestImpDetail.delta * 100).toFixed(2) + '% (gen ' + bestImpDetail.gen + ')' : 'n/a'}`,
  `- Total training: ${(trainingSecondsThis / 3600).toFixed(1)}h`,
  `- Avg duration / gen: ${totalThis ? Math.round(trainingSecondsThis / totalThis) + 's' : 'n/a'}`,
  '',
  `## Score trajectory (week-over-week)`,
  ...Object.entries(weekOverWeek).map(([k, d]) => `- **${k}**: ${thisWeekBench[k]?.toFixed(4) ?? 'n/a'}${d === null ? '' : ' (\u0394 ' + (d * 100).toFixed(2) + '%)'}`),
  '',
  `## Weakness focus`,
  `- Most-targeted weak categories: ${topWeak || 'n/a'}`,
].join('\n');

console.log('[weekly-summary]', { dateLabel, totalThis, promotedThis, discardedThis, rateThis });

return [{
  json: {
    date: dateLabel,
    champion_label: championLabel,
    champion_generation: championGen,
    lineage_depth: lineageDepth,
    promoted_this_week: promotedThis,
    discarded_this_week: discardedThis,
    total_this_week: totalThis,
    promoted_prev_week: promotedPrev,
    total_prev_week: totalPrev,
    promotion_rate_this_week: rateThis,
    promotion_rate_prev_week: ratePrev,
    training_hours_this_week: trainingSecondsThis / 3600,
    best_improvement: bestImpDetail,
    week_over_week: weekOverWeek,
    top_weak: topWeak,
    markdown: lines,
    slack_message: lines,
  }
}];
